// ── Reactive Controller (annotation style) ─────────────────
@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService service;
    UserController(UserService service) { this.service = service; }

    // Returns one user — Mono<T> (0 or 1 element)
    @GetMapping("/{id}")
    public Mono<ResponseEntity<User>> getUser(@PathVariable Long id) {
        return service.findById(id)
            .map(ResponseEntity::ok)
            .defaultIfEmpty(ResponseEntity.notFound().build());
    }

    // Returns all users — Flux<T> (0 to N elements)
    // Content-Type: application/json (collects all then sends)
    @GetMapping
    public Flux<User> getAllUsers() {
        return service.findAll();
    }

    // Server-Sent Events — streams items as they arrive
    @GetMapping(produces = MediaType.TEXT_EVENT_STREAM_VALUE)
    public Flux<User> streamUsers() {
        return service.findAll().delayElements(Duration.ofMillis(500));
    }
}

// ── Service using R2DBC reactive repository ─────────────────
@Service
public class UserService {
    private final UserRepository repo; // extends ReactiveCrudRepository
    UserService(UserRepository repo) { this.repo = repo; }

    public Mono<User> findById(Long id) { return repo.findById(id); }
    public Flux<User> findAll() { return repo.findAll(); }

    public Mono<User> create(User user) {
        return repo.save(user);
    }
}

// ── WebClient: calling another service ──────────────────────
@Component
public class ExternalApiClient {
    private final WebClient client;

    ExternalApiClient(WebClient.Builder builder) {
        this.client = builder.baseUrl("https://api.example.com").build();
    }

    public Mono<String> fetchData(String id) {
        return client.get()
            .uri("/data/{id}", id)
            .retrieve()
            .onStatus(HttpStatusCode::isError, resp ->
                resp.bodyToMono(String.class).map(RuntimeException::new))
            .bodyToMono(String.class)
            .timeout(Duration.ofSeconds(3))
            .onErrorReturn("fallback");
    }

    // Combining two async calls in parallel
    public Mono<CombinedResult> fetchBoth(String id) {
        return Mono.zip(
            fetchData(id),
            fetchData("meta-" + id),
            CombinedResult::new  // combinator
        );
    }
}

// ── Functional routing (alternative to @Controller) ─────────
@Configuration
public class RouterConfig {
    @Bean
    RouterFunction<ServerResponse> routes(UserHandler handler) {
        return RouterFunctions.route()
            .GET("/r/users/{id}", handler::getUser)
            .POST("/r/users",     handler::createUser)
            .build();
    }
}

@Component
public class UserHandler {
    private final UserService service;
    UserHandler(UserService service) { this.service = service; }

    public Mono<ServerResponse> getUser(ServerRequest req) {
        Long id = Long.parseLong(req.pathVariable("id"));
        return service.findById(id)
            .flatMap(u -> ServerResponse.ok().bodyValue(u))
            .switchIfEmpty(ServerResponse.notFound().build());
    }

    public Mono<ServerResponse> createUser(ServerRequest req) {
        return req.bodyToMono(User.class)
            .flatMap(service::create)
            .flatMap(u -> ServerResponse.created(URI.create("/r/users/" + u.id())).bodyValue(u));
    }
}

